function _decode(s){if(!s)return'';return s.split('').map((c,i)=>String.fromCharCode(c.charCodeAt(0)^((i%7)+3))).join('');}

w.CBT_QB = {
  get: function(subject){
    const raw = _QB[subject] || [];
    return raw.map(q=>({
      id: q.id,
      text: _decode(q.t),
      options: {
        A: _decode(q.o.A),
        B: _decode(q.o.B),
        C: _decode(q.o.C),
        D: _decode(q.o.D)
      },
      correct: q.c,
      explanation: _decode(q.e),
      year: q.y
    }));
  },
  subjects: ['english','mathematics','biology','chemistry','physics'],
  counts: {
    english: 123,
    mathematics: 70,
    biology: 127,
    chemistry: 141,
    physics: 92,
  }
};

